import React, { useState, useEffect, useRef, useCallback } from "react";
import axios from "axios";
import CameraIcon from "../../../../../../assets/camera.svg";
import { Row, Col, message, Card, Input } from "antd";
import { Button } from "semantic-ui-react";
import { useCorrectiveMaintenancePageHooks } from "./corrective-maintenance-page-hooks";
import MaintenanceContainer from "../maintenanceContainer";
import { StepContainer, StepData } from "../stepContainer/stepContainer";
import BarcodeScanner from "../components/barcode-scanner";
import {
  EquipmentInfo,
  EquipmentInfoRecord,
} from "../components/equipment-info/equipment-info";
import "./corrective-maintenance-page.css";

const CorrectiveMaintenancePage = () => {
  // const correctiveMaintenance = useCorrectiveMaintenancePageHooks();
  const [serial, setSerial] = useState("");
  const [isScannerOn, setIsScannerOn] = useState(false);
  const [equipmentInfo, setEquipmentInfo] = useState<
    EquipmentInfoRecord | undefined
  >(undefined);

  const steps: StepData[] = [
    {
      step: 1,
      title:
        "Scan the barcode or input the Asset Number/Serial Number directly",
    },
    { step: 2, title: "Upload T1 Capture" },
    { step: 3, title: "Upload Error Log" },
    { step: 4, title: "Useful recommendation(s)" },
  ];

  return (
    <div className="Page">
      <Card className="CardStyle">
        <StepContainer data={steps[0]}>
          <div>
            <Row className="Step1RowStyle">
              <Col flex={1}>
                <h3 className="Step1AssetNumberTitleStyle">
                  {"Asset Number/Serial Number"}
                </h3>
                <div className="Step1AssetNumberSearchStyle">
                  {
                    <div>
                      <Input
                        className="Step1SearchBoxStyle"
                        value={serial}
                        onChange={(e) => {
                          setSerial(e.target.value);
                          // setCurrentRecordOption({
                          //   title: e.target.value,
                          //   value: "",
                          // });
                        }}
                        size="large"
                      />
                      <Button
                        className="Step1CameraStyle"
                        icon={
                          <img
                            src={CameraIcon}
                            alt="EMSD"
                            onClick={() => {
                              setIsScannerOn(true);
                            }}
                          />
                        }
                      />
                      <Button
                        className="Step1SearchButtonStyle"
                        disabled={serial === undefined || serial === ""}
                        onClick={async () => {
                          axios
                            .get(
                              "https://emsdproject.work:52855/".concat(
                                "equipment-info-record/infoSpecific"
                              ),
                              {
                                params: {
                                  serial: serial,
                                },
                              }
                            )
                            .then((response) => {
                              setEquipmentInfo(response.data[0]);
                              setSerial(response.data[0].serial);
                            })
                            .catch((error) =>
                              console.error(
                                `Error Retrieving Equipment Information (Step 1): ${error}`
                              )
                            );
                        }}
                        size="large"
                      >
                        {"Confirm"}
                      </Button>
                    </div>
                  }
                </div>
              </Col>
              <Col flex={1}>
                <h3
                  style={{
                    fontSize: "12pt",
                    fontWeight: "normal",
                    marginLeft: "2vw",
                    textAlign: "left",
                  }}
                >
                  {"Task Number"}
                </h3>
                <div
                  style={{
                    display: "flex",
                    flexDirection: "row",
                    marginBottom: "8px",
                    alignItems: "flex-end",
                  }}
                >
                  {"something"}
                </div>
              </Col>
            </Row>
            <Row>
              {isScannerOn && (
                <BarcodeScanner
                  onScan={(result) => {
                    if (result.codeResult.code) {
                      setSerial(result.codeResult.code);
                      setIsScannerOn(false);
                    }
                  }}
                  onError={(err) => {
                    setIsScannerOn(false);
                    message.error(
                      "An error occurred. Please refresh and enable camera access."
                    );
                  }}
                />
              )}
              <br />
              <br style={{ padding: "3vh" }} />
              <Row
                style={{
                  display: "grid",
                  gridTemplateColumns: "1fr 1fr 1fr 1fr 1fr 1fr",
                  gridTemplateRows: "1fr",
                  paddingBottom: "3vh",
                }}
              >
                <Col flex={1}>
                  <EquipmentInfo
                    title="Asset Number"
                    value={equipmentInfo?.assetNumber || "-"}
                  />
                </Col>
                <Col flex={1}>
                  <EquipmentInfo
                    title="Serial Number"
                    value={equipmentInfo?.serial || "-"}
                  />
                </Col>
                <Col flex={1}>
                  <EquipmentInfo
                    title="Brand"
                    value={equipmentInfo?.brand || "-"}
                  />
                </Col>
                <Col flex={1}>
                  <EquipmentInfo
                    title="Model"
                    value={equipmentInfo?.model || "-"}
                  />
                </Col>
                <Col flex={1}>
                  <EquipmentInfo
                    title="Hospital"
                    value={equipmentInfo?.hospital || "-"}
                  />
                </Col>
                <Col flex={1}>
                  <EquipmentInfo
                    title="Health Score"
                    value={
                      equipmentInfo ? String(equipmentInfo.healthScore) : "-"
                    }
                  />
                </Col>
              </Row>
            </Row>
          </div>
        </StepContainer>
      </Card>
    </div>
  );
};

export default CorrectiveMaintenancePage;
